--
-- Create view `view_for_generate_tickets`
--
CREATE
DEFINER = 'root'@'localhost'
VIEW view_for_generate_tickets
AS
SELECT
  `t`.`ticket_id` AS `ticket_id`,
  `p`.`passenger_id` AS `passenger_id`,
  `p`.`last_name` AS `last_name`,
  `p`.`first_name` AS `first_name`,
  `p`.`patronymic` AS `patronymic`,
  CONCAT(`dep`.`city`, ' (', `dep`.`airport_code`, ')') AS `departure_city_code`,
  CONCAT(`arr`.`city`, ' (', `arr`.`airport_code`, ')') AS `arrival_city_code`,
  `v`.`departure_date` AS `departure_date`,
  `v`.`arrival_date` AS `arrival_date`,
  `s`.`seat_number` AS `seat`,
  `tf`.`tariff_name` AS `tariff`,
  `t`.`total_cost` AS `total_cost`
FROM ((((((`tickets` `t`
  JOIN `passengers` `p`
    ON ((`p`.`passenger_id` = `t`.`passenger_id`)))
  JOIN `voyages` `v`
    ON ((`v`.`voyage_id` = `t`.`voyage_id`)))
  JOIN `airports` `dep`
    ON ((`dep`.`airport_id` = `v`.`departure_airport_id`)))
  JOIN `airports` `arr`
    ON ((`arr`.`airport_id` = `v`.`arrival_airport_id`)))
  JOIN `seats` `s`
    ON ((`s`.`seat_id` = `t`.`seat_id`)))
  JOIN `tariffs` `tf`
    ON ((`tf`.`tariff_id` = `t`.`tariff_id`)));

