DELIMITER $$

--
-- Create trigger `trigger_append_voyage_and_seats_link`
--
CREATE
DEFINER = 'root'@'localhost'
TRIGGER trigger_append_voyage_and_seats_link
AFTER INSERT
ON voyages
FOR EACH ROW
BEGIN
  -- Объявляем переменные для итерации
  DECLARE done int DEFAULT 0;
  DECLARE current_seat_id int;

  -- Курсор для выборки всех seat_id для данного plane_id
  DECLARE seat_cursor CURSOR FOR
  SELECT
    seat_id
  FROM skytickets.seats
  WHERE plane_id = NEW.plane_id;

  -- Обработчик для окончания курсора
  DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;

  -- Открываем курсор
  OPEN seat_cursor;

-- Цикл по всем местам самолёта
read_loop:
  LOOP
    -- Получаем следующее seat_id
    FETCH seat_cursor INTO current_seat_id;

    -- Если больше нет записей — выходим из цикла
    IF done = 1 THEN
      LEAVE read_loop;
    END IF;

    -- Вставляем запись в таблицу-связку: место + рейс, статус «свободно»
    voyage_id,
    is_ordered)
      VALUES (current_seat_id, NEW.voyage_id, 0  -- 0 = свободно
      );
  END LOOP;

  -- Закрываем курсор
  CLOSE seat_cursor;
END
$$

DELIMITER ;

